-- ============================================================
-- ADIM 1: Yeni sütunlar ekle
-- ============================================================
ALTER TABLE public.indicators
  ADD COLUMN IF NOT EXISTS indicator_name_en TEXT,
  ADD COLUMN IF NOT EXISTS indicator_definition_en TEXT;

-- ============================================================
-- ADIM 2: Mevcut 137 KPI'ya İngilizce çeviri ekle
-- ============================================================

-- ARGE
UPDATE indicators SET indicator_name_en = 'Number of Patents per Year', indicator_definition_en = 'The total number of patents registered by the organization within a given year. Measures the level of innovative output and intellectual property generation.' WHERE indicator_name = 'Patent sayısı/yıl';
UPDATE indicators SET indicator_name_en = 'Return on Investment (ROI)', indicator_definition_en = 'The ratio of net profit from R&D investments to total R&D expenditure. Evaluates the financial efficiency and returns generated by research and development activities.' WHERE indicator_name = 'Yatırım Getirisi (ROI)';

-- BAKIM
UPDATE indicators SET indicator_name_en = 'Mean Time Between Failures (MTBF)', indicator_definition_en = 'The average operational time between consecutive equipment failures. A higher value indicates greater equipment reliability and less frequent breakdowns.' WHERE indicator_name = 'Arızalar Arası Ortalama Süre';
UPDATE indicators SET indicator_name_en = 'Average Maintenance Request Closure Time', indicator_definition_en = 'The average time taken from the opening to the closing of a maintenance request. Measures the responsiveness and efficiency of the maintenance team.' WHERE indicator_name = 'Bakım taleplerinin ortalama kapanma süresi';
UPDATE indicators SET indicator_name_en = 'Percentage of Overdue Maintenance Requests', indicator_definition_en = 'The proportion of maintenance requests that were not resolved within the agreed or expected timeframe. Indicates backlogs and process inefficiencies in maintenance management.' WHERE indicator_name = 'Gecikmiş bakım taleplerinin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Overall Equipment Effectiveness (OEE)', indicator_definition_en = 'A composite metric combining availability, performance, and quality to measure how effectively manufacturing equipment is utilized. A score of 100% represents perfect production.' WHERE indicator_name = 'Genel Ekipman Verimliliği (OEE)';
UPDATE indicators SET indicator_name_en = 'Overall Machine Efficiency', indicator_definition_en = 'The ratio of actual machine output to its maximum potential output over a defined period. Measures how productively machines are operating relative to their theoretical capacity.' WHERE indicator_name = 'Genel Makine Verimliliği';
UPDATE indicators SET indicator_name_en = 'Mean Time to Repair (MTTR)', indicator_definition_en = 'The average time required to repair a failed component or system and restore it to full operation. Lower values indicate faster and more effective repair processes.' WHERE indicator_name = 'Ortalama Onarım Süresi (MTTR)';
UPDATE indicators SET indicator_name_en = 'Mean Time to Detect (MTTD)', indicator_definition_en = 'The average time elapsed between the occurrence of a failure or incident and its detection. Shorter detection times enable faster response and reduced operational impact.' WHERE indicator_name = 'Ortalama Tespit Süresi (MTTD)';
UPDATE indicators SET indicator_name_en = 'Preventive Maintenance Effectiveness', indicator_definition_en = 'The ratio of successfully completed preventive maintenance tasks to all scheduled preventive maintenance activities. Measures how well the organization prevents failures before they occur.' WHERE indicator_name = 'Önleyici Bakım (PM) Etkinliği';
UPDATE indicators SET indicator_name_en = 'Total Maintenance Cost', indicator_definition_en = 'The total expenditure on all maintenance activities including labor, spare parts, and outsourced services over a defined period. Used to assess overall maintenance budget performance.' WHERE indicator_name = 'Toplam bakım maliyeti';
UPDATE indicators SET indicator_name_en = 'Total Number of Repairs', indicator_definition_en = 'The total count of repair activities performed on equipment and facilities within a given period. Higher counts may indicate aging equipment or inadequate preventive maintenance.' WHERE indicator_name = 'Toplam Onarım Sayısı';
UPDATE indicators SET indicator_name_en = 'Percentage of Incorrectly Assigned Maintenance Requests', indicator_definition_en = 'The proportion of maintenance requests that were routed to the wrong team or technician. Indicates issues in request categorization and dispatch processes.' WHERE indicator_name = 'Yanlış atanan bakım taleplerinin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Spare Parts Delivery Time', indicator_definition_en = 'The average time from ordering a spare part to its delivery at the maintenance site. Shorter delivery times reduce equipment downtime and improve maintenance responsiveness.' WHERE indicator_name = 'Yedek parça teslim süresi';
UPDATE indicators SET indicator_name_en = 'Percentage of Reopened Maintenance Requests', indicator_definition_en = 'The proportion of maintenance requests that were closed but subsequently reopened due to unresolved issues. A high rate indicates poor quality of maintenance resolution.' WHERE indicator_name = 'Yeniden açılan bakım taleplerinin yüzdesi';

-- BİLGİ TEKNOLOJİLERİ
UPDATE indicators SET indicator_name_en = 'Percentage of Incidents Bypassing Service Desk', indicator_definition_en = 'The proportion of IT incidents that were resolved without being registered through the service desk. High rates suggest informal workarounds that undermine IT governance.' WHERE indicator_name = 'Destek masasını atlayan olayların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Number of Recurring Errors', indicator_definition_en = 'The count of errors or defects that reappear after being previously fixed or resolved. Recurring errors indicate inadequate root cause analysis or incomplete fixes.' WHERE indicator_name = 'Geri dönen hata sayısı';
UPDATE indicators SET indicator_name_en = 'Percentage of Positively Resolved Cases', indicator_definition_en = 'The proportion of IT support cases resolved to the satisfaction of the end user. Measures service desk effectiveness and user experience quality.' WHERE indicator_name = 'Olumlu şekilde çözülen vakaların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Average Penalty Costs per SLA', indicator_definition_en = 'The average financial penalties incurred per Service Level Agreement due to SLA breaches. Tracks the financial impact of failing to meet committed service levels.' WHERE indicator_name = 'SLA başına ortalama ceza maliyetleri';
UPDATE indicators SET indicator_name_en = 'SLA Budget Deviation', indicator_definition_en = 'The variance between the planned budget for SLA compliance and the actual costs incurred. Significant deviations indicate poor SLA cost estimation or unplanned service failures.' WHERE indicator_name = 'SLA için planlanan bütçenin sapması';
UPDATE indicators SET indicator_name_en = 'Number of Bugs per Release', indicator_definition_en = 'The average number of defects identified per software release. Lower counts indicate higher code quality and more rigorous testing processes.' WHERE indicator_name = 'Sürüm başına hata sayısı';
UPDATE indicators SET indicator_name_en = 'Average Processing Cost per Release', indicator_definition_en = 'The total cost associated with deploying a software release divided by the number of releases. Helps evaluate the efficiency and cost-effectiveness of the deployment pipeline.' WHERE indicator_name = 'Sürüm başına ortalama işlem maliyeti';
UPDATE indicators SET indicator_name_en = 'Percentage of Incorrectly Assigned Service Requests', indicator_definition_en = 'The share of service requests routed to the wrong team or department for resolution. High rates indicate problems in request classification and assignment workflows.' WHERE indicator_name = 'Yanlış atanan hizmet isteklerinin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Incorrectly Assigned Incidents', indicator_definition_en = 'The share of incidents that were initially assigned to the wrong support group. Incorrect assignment increases resolution time and reduces service quality.' WHERE indicator_name = 'Yanlış atanan olayların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Reopened Service Requests', indicator_definition_en = 'The proportion of service requests that were closed but later reopened because the issue persisted. Indicates inadequate initial resolution and impacts user satisfaction.' WHERE indicator_name = 'Yeniden açılan hizmet isteklerinin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Reopened Incidents', indicator_definition_en = 'The proportion of incidents that were closed but subsequently reopened due to recurrence. A key indicator of resolution quality and the thoroughness of root cause elimination.' WHERE indicator_name = 'Yeniden açılan olayların yüzdesi';

-- FİNANS
UPDATE indicators SET indicator_name_en = 'Cost per Invoice, Supplier', indicator_definition_en = 'The average cost incurred to process a single supplier invoice, including labor, system, and overhead costs. Lower costs indicate a more efficient accounts payable process.' WHERE indicator_name = 'Fatura Başına Maliyet, Tedarikçi';
UPDATE indicators SET indicator_name_en = 'Operating Profit Margin', indicator_definition_en = 'The ratio of operating profit to total revenue, expressed as a percentage. It measures how efficiently a company generates profit from its core business operations.' WHERE indicator_name = 'Faaliyet kar marjı';
UPDATE indicators SET indicator_name_en = 'Cost per Invoice, Customer', indicator_definition_en = 'The average cost to generate and process a single customer invoice. Monitoring this metric helps identify opportunities to streamline accounts receivable processes.' WHERE indicator_name = 'Fatura Başına Maliyet, Müşteri';
UPDATE indicators SET indicator_name_en = 'Invoice Discrepancy Cost', indicator_definition_en = 'The total financial cost associated with resolving invoice discrepancies, including dispute resolution, rework, and write-offs. High values indicate invoice accuracy issues.' WHERE indicator_name = 'Fatura Tutarsızlığı Maliyeti';
UPDATE indicators SET indicator_name_en = 'Gross Profit per Share', indicator_definition_en = 'The gross profit divided by the total number of outstanding shares. Provides investors with insight into the profitability attributable to each share of stock.' WHERE indicator_name = 'Hisse başına brüt kar';
UPDATE indicators SET indicator_name_en = 'Percentage of Cancelled Payments', indicator_definition_en = 'The proportion of payment transactions that were initiated but subsequently cancelled before completion. High rates may indicate process inefficiencies or data quality issues.' WHERE indicator_name = 'İptal edilen ödemelerin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Profit Margin, Actual', indicator_definition_en = 'The actual net profit margin achieved during a reporting period compared to targets. It reflects the overall financial health and cost management effectiveness of the organization.' WHERE indicator_name = 'Kar Marjı, Gerçek';
UPDATE indicators SET indicator_name_en = 'Deviation from Planned Break-Even Time', indicator_definition_en = 'The difference between the projected and actual time required to reach the break-even point. Significant deviations indicate challenges in revenue generation or cost management.' WHERE indicator_name = 'Planlanan başabaş zamanından sapma';
UPDATE indicators SET indicator_name_en = 'Budget Deviation', indicator_definition_en = 'The variance between the planned budget and actual expenditure over a given period. Tracking this metric ensures financial discipline and early identification of overspending.' WHERE indicator_name = 'Planlanan bütçenin sapması';
UPDATE indicators SET indicator_name_en = 'Total Assets', indicator_definition_en = 'The combined value of all assets owned by the organization at a given point in time. A key balance sheet figure used to assess the overall size and resource base of the company.' WHERE indicator_name = 'Toplam Varlıklar';
UPDATE indicators SET indicator_name_en = 'Pre-Tax Operating Return on Total Assets', indicator_definition_en = 'The ratio of pre-tax operating profit to total assets. Measures how efficiently the company uses its total asset base to generate operating profits before tax.' WHERE indicator_name = 'Toplam varlıklar üzerinden vergi öncesi faaliyet getirisi';
UPDATE indicators SET indicator_name_en = 'Sales Return on Total Assets', indicator_definition_en = 'The ratio of total revenue to total assets, indicating how efficiently assets are used to generate sales. Higher values suggest more productive asset utilization.' WHERE indicator_name = 'Toplam varlıklara satış getirisi';
UPDATE indicators SET indicator_name_en = 'Ratio of Overdue Accounts Payable to Total Payables', indicator_definition_en = 'The proportion of total accounts payable that has exceeded payment due dates. High ratios may damage supplier relationships and indicate cash flow challenges.' WHERE indicator_name = 'Vadesi geçen hesap borçlarının toplam borçlara oranı';
UPDATE indicators SET indicator_name_en = 'Ratio of Overdue Receivables to Total Receivables', indicator_definition_en = 'The share of total accounts receivable that has passed the payment due date. A high ratio signals collection problems and potential cash flow risks.' WHERE indicator_name = 'Vadesi geçmiş alacakların toplam alacaklara oranı';
UPDATE indicators SET indicator_name_en = 'Number of Overdue Invoices', indicator_definition_en = 'The total count of invoices that have not been paid or processed by their due date. Monitoring this helps identify bottlenecks in accounts receivable or payable workflows.' WHERE indicator_name = 'Vadesi geçmiş fatura sayısı';
UPDATE indicators SET indicator_name_en = 'Average Monetary Value of Overdue Invoices', indicator_definition_en = 'The average financial value of invoices that remain unpaid past their due date. Higher average values indicate larger cash flow exposure from overdue accounts.' WHERE indicator_name = 'Vadesi geçmiş faturaların ortalama parasal değeri';
UPDATE indicators SET indicator_name_en = 'Percentage of Overdue Invoices', indicator_definition_en = 'The proportion of total invoices that are past their due date. This metric helps assess collection efficiency and the risk of bad debts within the receivables portfolio.' WHERE indicator_name = 'Vadesi geçmiş faturaların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Number of Overdue Credits', indicator_definition_en = 'The count of credit notes or credit transactions that have not been applied or settled by the agreed date. Indicates delays in credit processing or reconciliation.' WHERE indicator_name = 'Vadesi geçmiş kredi sayısı';
UPDATE indicators SET indicator_name_en = 'Average Value of Overdue Credits', indicator_definition_en = 'The mean monetary value of credits that remain unresolved past their due date. Used to gauge the magnitude of outstanding credit exposure.' WHERE indicator_name = 'Vadesi geçmiş kredilerin ortalama değeri';
UPDATE indicators SET indicator_name_en = 'Total Value of Overdue Credits', indicator_definition_en = 'The aggregate financial value of all overdue credits outstanding at a given point in time. A key metric for assessing total credit risk exposure.' WHERE indicator_name = 'Vadesi geçmiş kredilerin toplam değeri';
UPDATE indicators SET indicator_name_en = 'Percentage of Overdue Domestic Receivables', indicator_definition_en = 'The proportion of domestic accounts receivable that has exceeded payment terms. Tracks collection efficiency specifically within the home market.' WHERE indicator_name = 'vadesi geçmiş ulusal alacakların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Overdue Domestic Invoices', indicator_definition_en = 'The share of invoices issued to domestic customers that remain unpaid after the due date. Helps identify collection issues specific to the local market.' WHERE indicator_name = 'Vadesi geçmiş ulusal faturaların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Overdue International Receivables', indicator_definition_en = 'The proportion of foreign accounts receivable that has exceeded payment terms. International overdue receivables carry additional risk due to currency and regulatory factors.' WHERE indicator_name = 'vadesi geçmiş uluslararası alacakların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Overdue International Invoices', indicator_definition_en = 'The share of invoices issued to international customers that are past due. Monitoring this helps manage cross-border collection risks and foreign receivables exposure.' WHERE indicator_name = 'Vadesi geçmiş uluslararası faturaların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Reopened Insurance Claims', indicator_definition_en = 'The proportion of insurance claims that were closed but subsequently reopened for further review or settlement. High rates may indicate initial claim handling quality issues.' WHERE indicator_name = 'Yeniden açılan sigorta taleplerinin yüzdesi';

-- KALİTE
UPDATE indicators SET indicator_name_en = 'Test KPI', indicator_definition_en = 'A placeholder or test entry used during system validation and testing phases.' WHERE indicator_name = 'Test KPI';
UPDATE indicators SET indicator_name_en = 'Percentage of KPIs Outside Defined Targets', indicator_definition_en = 'The proportion of organizational KPIs whose actual values fall outside their defined target ranges. Indicates how many performance areas require corrective action.' WHERE indicator_name = 'Belirlenen hedeflerin dışındaki KPI''ların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Number of Delayed Audits', indicator_definition_en = 'The count of internal or external audits that were not conducted on their scheduled dates. Delays in audits reduce oversight effectiveness and may indicate resource constraints.' WHERE indicator_name = 'Gecikmiş denetim sayısı';
UPDATE indicators SET indicator_name_en = 'Minor Findings Count in ISO 9001 Internal Audit', indicator_definition_en = 'The number of minor non-conformances identified during ISO 9001 internal audits. Tracking minor findings helps prevent their escalation into major quality issues.' WHERE indicator_name = 'ISO 9001 iç denetimde minör bulgu sayısı';
UPDATE indicators SET indicator_name_en = 'Percentage of Issues Addressed with Root Cause Analysis', indicator_definition_en = 'The proportion of quality issues or non-conformances for which a formal root cause analysis was performed. Higher rates indicate a more systematic approach to problem resolution.' WHERE indicator_name = 'Kök neden analiziyle ilgili sorunların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Issues with Identified Root Cause', indicator_definition_en = 'The share of analyzed quality issues for which the root cause was successfully identified. A higher rate demonstrates the effectiveness of the root cause analysis process.' WHERE indicator_name = 'Kök nedeni tespit edilen sorunların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Process Audit Effectiveness', indicator_definition_en = 'A measure of how effectively internal process audits identify non-conformances and drive corrective actions. High effectiveness indicates that audits are adding real value to process improvement.' WHERE indicator_name = 'Süreç Denetimlerinin Etkinliği';
UPDATE indicators SET indicator_name_en = 'Value of Process Improvements', indicator_definition_en = 'The quantified financial or operational value generated by process improvement initiatives. Helps justify investment in continuous improvement programs and quality management systems.' WHERE indicator_name = 'Süreç İyileştirmelerinin Değeri';
UPDATE indicators SET indicator_name_en = 'Complaint Resolution Rate', indicator_definition_en = 'The percentage of customer or internal complaints that were successfully resolved within the target timeframe. A high rate reflects effective complaint management and customer service processes.' WHERE indicator_name = 'Şikayet çözüm oranı';

-- SATIŞ VE PAZARLAMA
UPDATE indicators SET indicator_name_en = 'Percentage of Incorrectly Delivered Shipments', indicator_definition_en = 'The proportion of total deliveries that were delivered incorrectly (wrong item, quantity, or location). A key indicator of order fulfillment accuracy and logistics quality.' WHERE indicator_name = 'Doğru şekilde teslim edilmeyen teslimatların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Incorrectly Delivered Domestic Shipments', indicator_definition_en = 'The share of domestic deliveries that did not meet accuracy standards. Helps pinpoint fulfillment issues specific to the local distribution network.' WHERE indicator_name = 'Doğru şekilde teslim edilmeyen ulusal teslimatların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Incorrectly Delivered International Shipments', indicator_definition_en = 'The proportion of international deliveries made inaccurately. International delivery errors often carry higher costs due to cross-border logistics and customs complexity.' WHERE indicator_name = 'Doğru şekilde teslim edilmeyen uluslararası teslimatların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Quantity per Shipment', indicator_definition_en = 'The average number of units included in a single shipment. Monitoring this metric helps optimize shipping frequencies and costs against order volumes.' WHERE indicator_name = 'Gönderi başına miktar';
UPDATE indicators SET indicator_name_en = 'Average Revenue per User (ARPU)', indicator_definition_en = 'The average monthly revenue generated per active customer. A critical metric for subscription and recurring revenue businesses to assess monetization efficiency.' WHERE indicator_name = 'Müşteri başına ortalama aylık gelir (ARPU)';
UPDATE indicators SET indicator_name_en = 'Average Spend per Customer', indicator_definition_en = 'The average total expenditure of a customer over a defined period. Higher values indicate greater wallet share capture and stronger customer engagement.' WHERE indicator_name = 'Müşteri Başına Ortalama Harcama';
UPDATE indicators SET indicator_name_en = 'Average Profit per Customer', indicator_definition_en = 'The average net profit generated from each customer after deducting all associated costs. Helps segment customers by profitability and focus resources on high-value accounts.' WHERE indicator_name = 'Müşteri Başına Ortalama Kar';
UPDATE indicators SET indicator_name_en = 'Customer Growth Rate', indicator_definition_en = 'The percentage increase in the total number of customers over a defined period. A positive growth rate indicates successful acquisition strategies and market expansion.' WHERE indicator_name = 'Müşteri Büyüme Oranı';
UPDATE indicators SET indicator_name_en = 'Customer Retention Rate', indicator_definition_en = 'The percentage of customers retained over a specific period without churning. High retention rates indicate strong customer satisfaction and loyalty, reducing the need for costly acquisition.' WHERE indicator_name = 'Müşteri Elde Tutma Oranı';
UPDATE indicators SET indicator_name_en = 'Customer Profitability Margin', indicator_definition_en = 'The profit margin generated from a customer or customer segment after deducting all service and acquisition costs. Identifies which customer groups contribute most to overall profitability.' WHERE indicator_name = 'Müşteri Karlılık Marjı';
UPDATE indicators SET indicator_name_en = 'Customer Satisfaction Index', indicator_definition_en = 'A composite score measuring overall customer satisfaction based on surveys and feedback. It provides a holistic view of how well the organization meets customer expectations.' WHERE indicator_name = 'Müşteri Memnuniyeti Endeksi';
UPDATE indicators SET indicator_name_en = 'Customer Complaint Rate', indicator_definition_en = 'The number of customer complaints received per total customers or transactions over a period. A lower rate indicates higher product quality and service levels.' WHERE indicator_name = 'Müşteri Şikayet Oranı';
UPDATE indicators SET indicator_name_en = 'Market Coverage Rate', indicator_definition_en = 'The percentage of the target market that the organization''s products or services currently reach. Higher coverage indicates broader market penetration and distribution effectiveness.' WHERE indicator_name = 'Pazar Kapsama Oranı';
UPDATE indicators SET indicator_name_en = 'Market Share %', indicator_definition_en = 'The percentage of total industry or segment sales captured by the organization. A key competitive metric reflecting the company''s relative position within its market.' WHERE indicator_name = 'Pazar payı %';
UPDATE indicators SET indicator_name_en = 'Market Segment Growth Rate', indicator_definition_en = 'The rate of growth within a specific market segment over a defined period. Understanding segment growth helps prioritize resource allocation and strategic focus areas.' WHERE indicator_name = 'Pazar Segmenti Büyüme Hızı';
UPDATE indicators SET indicator_name_en = 'Revenue per Ad Click', indicator_definition_en = 'The average revenue generated for each click on an advertisement. Measures the direct revenue efficiency of pay-per-click and digital advertising campaigns.' WHERE indicator_name = 'Reklam tıklaması başına gelir';
UPDATE indicators SET indicator_name_en = 'SaaS Customer Margin Rate', indicator_definition_en = 'The gross margin generated from SaaS customers after deducting hosting, support, and service delivery costs. A critical metric for assessing the unit economics of SaaS business models.' WHERE indicator_name = 'SaaS müşteri marj oranı';
UPDATE indicators SET indicator_name_en = 'Average Days to Purchase', indicator_definition_en = 'The average number of days from a customer''s first interaction to their first purchase. Shorter cycles indicate a more effective sales funnel and customer conversion process.' WHERE indicator_name = 'Satın Almak İçin Ortalama Gün';
UPDATE indicators SET indicator_name_en = 'Average Visits to Purchase', indicator_definition_en = 'The average number of website or store visits a customer makes before completing a purchase. Fewer visits suggest a more streamlined and persuasive customer journey.' WHERE indicator_name = 'Satın Almak İçin Ortalama Ziyaret';
UPDATE indicators SET indicator_name_en = 'Sales Return Rate', indicator_definition_en = 'The proportion of sold products returned by customers. A high return rate may indicate product quality issues, misaligned expectations, or fulfillment errors.' WHERE indicator_name = 'Satış İade Oranı';
UPDATE indicators SET indicator_name_en = 'Sales Rate %', indicator_definition_en = 'The percentage of available inventory or leads that were converted into actual sales. A core measure of sales efficiency and product/market demand alignment.' WHERE indicator_name = 'Satış oranı %';
UPDATE indicators SET indicator_name_en = 'Order Fill Rate, Customer', indicator_definition_en = 'The percentage of customer orders fulfilled completely from available stock on the first attempt. High fill rates indicate strong inventory management and customer service performance.' WHERE indicator_name = 'Sipariş Doldurma Oranı, Müşteri';
UPDATE indicators SET indicator_name_en = 'Order Fill Rate, Supplier', indicator_definition_en = 'The percentage of purchase orders fulfilled completely by suppliers on the first delivery attempt. Tracks supplier reliability and the adequacy of the supply chain.' WHERE indicator_name = 'Sipariş Doldurma Oranı, Tedarikçi';
UPDATE indicators SET indicator_name_en = 'Percentage of Orders Delivered to Customer on Committed Date', indicator_definition_en = 'The share of customer orders delivered on the exact date that was originally committed. A direct measure of delivery reliability and supply chain performance.' WHERE indicator_name = 'Taahhüt edilen tarihte müşteriye teslim edilen siparişlerin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Orders Delivered by Committed Date', indicator_definition_en = 'The proportion of orders delivered on or before the committed delivery date. Reflects overall on-time delivery performance across the organization.' WHERE indicator_name = 'Taahhüt Tarihine Göre Teslim Edilen Siparişlerin Yüzdesi';
UPDATE indicators SET indicator_name_en = 'Quote Conversion Rate', indicator_definition_en = 'The percentage of sales quotes or proposals that result in a confirmed order. A higher conversion rate indicates a more effective sales process and competitive offering.' WHERE indicator_name = 'Teklif dönüşüm oranı';
UPDATE indicators SET indicator_name_en = 'Percentage of Undelivered Shipments', indicator_definition_en = 'The proportion of shipments that failed to reach their intended destination. Undelivered shipments lead to customer dissatisfaction and additional logistics costs.' WHERE indicator_name = 'Teslim edilmeyen teslimatların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Undelivered Domestic Shipments', indicator_definition_en = 'The share of domestic shipments that were not successfully delivered. Helps identify failures within the local logistics network.' WHERE indicator_name = 'Teslim edilmeyen ulusal teslimatların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Percentage of Undelivered International Shipments', indicator_definition_en = 'The proportion of international shipments that failed delivery. Cross-border undelivered shipments are particularly costly due to return logistics and customs procedures.' WHERE indicator_name = 'Teslim edilmeyen uluslararası teslimatların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Profit per Delivery', indicator_definition_en = 'The net profit generated per individual delivery, after deducting all shipping and handling costs. Helps assess the profitability of the distribution model.' WHERE indicator_name = 'Teslimat başına kar';
UPDATE indicators SET indicator_name_en = 'New Customer Retention Rate', indicator_definition_en = 'The percentage of newly acquired customers who remain active after a defined initial period. A key indicator of onboarding effectiveness and early-stage customer experience.' WHERE indicator_name = 'Yeni Müşteri Elde Tutma Oranı';
UPDATE indicators SET indicator_name_en = 'Percentage of Reopened Orders', indicator_definition_en = 'The proportion of sales or purchase orders that were closed but later reopened due to unresolved issues. Indicates problems in order completion or fulfillment accuracy.' WHERE indicator_name = 'Yeniden açılan siparişlerin yüzdesi';

-- TEDARİK ZİNCİRİ
UPDATE indicators SET indicator_name_en = 'Average Variable Costs per Shipment', indicator_definition_en = 'The average variable costs incurred per shipment, including fuel, packaging, and handling fees. Monitoring variable costs helps identify efficiency opportunities in logistics operations.' WHERE indicator_name = 'Gemi başına ortalama değişken maliyetler';
UPDATE indicators SET indicator_name_en = 'Average Fixed Costs per Shipment', indicator_definition_en = 'The average fixed overhead costs allocated per shipment, such as warehouse lease and fleet depreciation. Understanding fixed cost allocation helps optimize shipment frequency and volume.' WHERE indicator_name = 'Gemi başına ortalama sabit maliyetler';
UPDATE indicators SET indicator_name_en = 'Days Sales of Inventory (DSI)', indicator_definition_en = 'The average number of days it takes to sell the entire inventory on hand. Lower DSI values indicate faster inventory turnover and more efficient stock management.' WHERE indicator_name = 'Gün Stok Satışı ';
UPDATE indicators SET indicator_name_en = 'Average Cost per Movement', indicator_definition_en = 'The average cost associated with each physical movement of goods within the supply chain. Tracking this metric helps identify cost reduction opportunities in material handling.' WHERE indicator_name = 'Hareket başına ortalama maliyet';
UPDATE indicators SET indicator_name_en = 'Average Purchase Order Processing Cost', indicator_definition_en = 'The average cost to process a single purchase order from creation to fulfillment. Lower processing costs indicate a more efficient procurement function.' WHERE indicator_name = 'Ortalama satınalma siparişi işleme maliyeti';
UPDATE indicators SET indicator_name_en = 'Average Processing Cost per Purchase Order Request', indicator_definition_en = 'The mean cost associated with processing each purchase order request submitted to procurement. Helps identify inefficiencies in the requisition-to-order workflow.' WHERE indicator_name = 'Satınalma siparişi istekleri başına ortalama işleme maliyeti';
UPDATE indicators SET indicator_name_en = 'Average Days Purchase Order Requests Remain Open', indicator_definition_en = 'The average number of days a purchase order request remains open before being approved or rejected. Long open times indicate bottlenecks in the procurement approval process.' WHERE indicator_name = 'Satınalma siparişi isteklerinin açık olduğu ortalama gün sayısı';
UPDATE indicators SET indicator_name_en = 'Percentage of Reopened Purchase Order Requests', indicator_definition_en = 'The share of purchase order requests that were closed and subsequently reopened. Reopened requests indicate errors or incomplete information in the initial submission.' WHERE indicator_name = 'Yeniden açılan satınalma siparişi isteklerinin yüzdesi';

-- ÇEVRE
UPDATE indicators SET indicator_name_en = 'CO2 Tons per Employee', indicator_definition_en = 'The total CO2 emissions generated by the organization divided by the number of employees. A per-capita environmental metric used to benchmark sustainability performance.' WHERE indicator_name = 'Çalışan başına CO2 Ton';
UPDATE indicators SET indicator_name_en = 'Daily Household Waste Generation per Person', indicator_definition_en = 'The average amount of solid waste generated per person per day at the facility or community level. Lower values indicate more effective waste reduction and management practices.' WHERE indicator_name = 'Kişi başına günlük evsel atık üretimi';
UPDATE indicators SET indicator_name_en = 'Daily Water Consumption per Person', indicator_definition_en = 'The average volume of water consumed per person per day in the organization''s operations. Monitoring this helps drive water conservation initiatives and reduce operational costs.' WHERE indicator_name = 'Kişi başına günlük su tüketimi';

-- ÜRETİM
UPDATE indicators SET indicator_name_en = 'Resource Utilization (%)', indicator_definition_en = 'The percentage of available resources (labor, equipment, materials) actually utilized in production. Higher utilization rates indicate more efficient use of organizational assets.' WHERE indicator_name = 'Kaynak kullanımı (%)';
UPDATE indicators SET indicator_name_en = 'Average Part Quality Index', indicator_definition_en = 'A composite quality score that measures the average quality level of manufactured parts. A higher index value indicates fewer defects and closer conformance to specifications.' WHERE indicator_name = 'Ortalama parça kalite endeksi';
UPDATE indicators SET indicator_name_en = 'Average Deviation from Planned Project Budget', indicator_definition_en = 'The average variance between planned and actual project budgets across all active projects. Positive deviations indicate budget overruns that may require management intervention.' WHERE indicator_name = 'Planlanan proje bütçesinin ortalama sapması';
UPDATE indicators SET indicator_name_en = 'Total Deviation from Planned Project Budget', indicator_definition_en = 'The cumulative total of all budget overruns or savings across all projects. Provides a high-level view of overall budget management performance.' WHERE indicator_name = 'Planlanan proje bütçesinin toplam sapması';
UPDATE indicators SET indicator_name_en = 'Schedule Completion Effectiveness (%)', indicator_definition_en = 'The percentage of production or project tasks completed on schedule. High effectiveness indicates good planning accuracy and strong execution discipline.' WHERE indicator_name = 'Program Tamamlama Etkinliği (%)';
UPDATE indicators SET indicator_name_en = 'Energy Costs per Production Unit', indicator_definition_en = 'The total energy cost incurred to produce a single unit of output. Tracking this metric helps identify opportunities to reduce energy consumption and improve cost efficiency.' WHERE indicator_name = 'Üretim birimi başına enerji maliyetleri';
UPDATE indicators SET indicator_name_en = 'Total Energy Used per Production Unit', indicator_definition_en = 'The total amount of energy (in kWh or equivalent) consumed to produce one unit of output. Lower values indicate more energy-efficient production processes.' WHERE indicator_name = 'Üretim birimi başına kullanılan toplam enerji';
UPDATE indicators SET indicator_name_en = 'Production Absenteeism Rate', indicator_definition_en = 'The rate of unplanned absences among production employees during a given period. High absenteeism disrupts production schedules and increases overtime costs.' WHERE indicator_name = 'Üretim Devamsızlık Oranı';
UPDATE indicators SET indicator_name_en = 'Production Labor Utilization', indicator_definition_en = 'The ratio of productive labor hours to total available labor hours on the production floor. Higher utilization indicates better workforce scheduling and less idle time.' WHERE indicator_name = 'Üretim Emek Kullanımı';
UPDATE indicators SET indicator_name_en = 'Production Capacity Effectiveness', indicator_definition_en = 'A measure of how effectively the available production capacity is being used to meet output targets. It combines utilization and performance rates to give an overall view of capacity performance.' WHERE indicator_name = 'Üretim Kapasitesi Etkinliği';
UPDATE indicators SET indicator_name_en = 'Production Capacity Utilization', indicator_definition_en = 'The percentage of total production capacity that is currently being used. Operating near optimal utilization maximizes fixed cost absorption without creating bottlenecks.' WHERE indicator_name = 'Üretim Kapasitesi Kullanımı';
UPDATE indicators SET indicator_name_en = 'Production Capacity Efficiency', indicator_definition_en = 'The ratio of actual production output to the theoretical maximum output under optimal conditions. It measures how efficiently the production process converts available capacity into finished goods.' WHERE indicator_name = 'Üretim Kapasitesi Verimlilik';
UPDATE indicators SET indicator_name_en = 'Profit per Product', indicator_definition_en = 'The net profit generated from selling a single unit of a product after all associated costs. Helps identify the most and least profitable products within the portfolio.' WHERE indicator_name = 'Ürün başına kar';
UPDATE indicators SET indicator_name_en = 'Percentage of Incorrectly Assigned Project Tasks', indicator_definition_en = 'The proportion of project tasks assigned to the wrong team or individual. Incorrect assignments lead to delays, rework, and reduced project efficiency.' WHERE indicator_name = 'Yanlış atanan proje görevlerinin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Number of Incidents Due to Insufficient Capacity', indicator_definition_en = 'The count of operational incidents or service disruptions caused by inadequate production or resource capacity. Reducing this metric requires proactive capacity planning.' WHERE indicator_name = 'Yetersiz Kapasiteden Kaynaklanan Olay Sayısı';

-- İNSAN KAYNAKLARI
UPDATE indicators SET indicator_name_en = 'Number of Payroll Payment Errors', indicator_definition_en = 'The total count of errors identified in payroll processing during a given period. Payroll errors damage employee trust and may result in legal and financial penalties.' WHERE indicator_name = 'Bordro ödeme hatası sayısı';
UPDATE indicators SET indicator_name_en = 'Average Absenteeism per Employee', indicator_definition_en = 'The average number of unplanned absence days per employee over a defined period. High absenteeism rates indicate potential issues with employee well-being or workplace culture.' WHERE indicator_name = 'Çalışan başına ortalama devamsızlık';
UPDATE indicators SET indicator_name_en = 'Management Cost per Employee', indicator_definition_en = 'The total management overhead cost divided by the number of employees. Monitoring this ratio helps ensure that management layers are cost-effective and appropriately sized.' WHERE indicator_name = 'Çalışan başına yönetim maliyeti';
UPDATE indicators SET indicator_name_en = 'Total Time Lost Due to Overtime', indicator_definition_en = 'The cumulative hours lost or added due to unplanned overtime work. Excessive overtime can signal understaffing or poor workload management and increases burnout risk.' WHERE indicator_name = 'Geç çalışma nedeniyle kaybedilen toplam süre';
UPDATE indicators SET indicator_name_en = 'Number of Incidents per Developed Application', indicator_definition_en = 'The average number of operational incidents attributed to each internally developed application. A lower count indicates higher application quality and stability.' WHERE indicator_name = 'Geliştirilen uygulama başına olay sayısı';
UPDATE indicators SET indicator_name_en = 'Recruitment Success Rate', indicator_definition_en = 'The percentage of recruited employees who successfully complete their probationary period and remain with the organization. A high rate reflects effective hiring and onboarding processes.' WHERE indicator_name = 'İşe alım başarı yüzdesi';
UPDATE indicators SET indicator_name_en = 'Hiring Manager Satisfaction Rate', indicator_definition_en = 'The percentage of hiring managers who are satisfied with the quality of candidates provided by the HR recruitment process. Reflects alignment between HR and business talent requirements.' WHERE indicator_name = 'İşe alım yöneticisi memnuniyet oranı yüzdesi';
UPDATE indicators SET indicator_name_en = 'Employer Satisfaction Index', indicator_definition_en = 'A composite index measuring overall employee satisfaction with their employer and working conditions. A high index correlates with lower turnover, higher productivity, and stronger culture.' WHERE indicator_name = 'İşveren memnuniyeti (endeks)';
UPDATE indicators SET indicator_name_en = 'Percentage of Monitoring Coverage', indicator_definition_en = 'The proportion of critical business processes or employees covered by performance monitoring systems. Higher coverage enables more comprehensive oversight and early detection of performance issues.' WHERE indicator_name = 'İzleme kapsamının yüzdesi';
UPDATE indicators SET indicator_name_en = 'Average Staff Turnover Cost', indicator_definition_en = 'The average total cost of replacing a single employee, including recruitment, onboarding, and productivity loss. Reducing turnover costs requires improving retention and engagement programs.' WHERE indicator_name = 'Ortalama personel devir maliyeti';
UPDATE indicators SET indicator_name_en = 'Deviation from Planned Working Hours', indicator_definition_en = 'The difference between planned and actual working hours for employees over a given period. Significant deviations may indicate scheduling inefficiencies or workload imbalances.' WHERE indicator_name = 'Planlanan çalışma saatlerinden sapma';

-- İŞ SAĞLIĞI VE GÜVENLİĞİ
UPDATE indicators SET indicator_name_en = 'Average Number of Sick Days per Employee', indicator_definition_en = 'The average number of sick leave days taken per employee over a defined period. Monitoring this helps identify health trends and evaluate the effectiveness of employee wellness programs.' WHERE indicator_name = 'Çalışan başına ortalama hastalık günü sayısı';
UPDATE indicators SET indicator_name_en = 'Time Lost Due to Accidents per Hours Worked (incl. fatalities)', indicator_definition_en = 'The total hours of work lost due to workplace accidents, including fatal incidents, per total hours worked. A key safety performance metric used in industry benchmarking.' WHERE indicator_name = 'Çalışılan saat başına kaza nedeniyle kaybedilen zaman (ölümler dahil)';
UPDATE indicators SET indicator_name_en = 'Reportable Accidents per Hours Worked (incl. fatalities)', indicator_definition_en = 'The frequency rate of recordable workplace accidents per total hours worked, including fatal accidents. Widely used to compare safety performance across industries and sites.' WHERE indicator_name = 'Çalışılan saat başına rapor edilebilir kazalar (ölümler dahil)';
UPDATE indicators SET indicator_name_en = 'Percentage of Unassessed Risks', indicator_definition_en = 'The proportion of identified workplace hazards or risks that have not yet undergone formal risk assessment. High percentages indicate gaps in the organization''s risk management process.' WHERE indicator_name = 'Değerlendirilmemiş risklerin yüzdesi';
UPDATE indicators SET indicator_name_en = 'Average Sick Days per FTE', indicator_definition_en = 'The mean number of sick days per full-time equivalent employee. Normalizing by FTE allows fair comparison across departments or sites of different sizes.' WHERE indicator_name = 'FTE başına ortalama hastalık günleri';
UPDATE indicators SET indicator_name_en = 'Average Losses per FTE', indicator_definition_en = 'The average financial loss attributable to workplace incidents per full-time equivalent employee. Used to quantify the economic impact of safety failures on the organization.' WHERE indicator_name = 'FTE başına ortalama kayıplar';
UPDATE indicators SET indicator_name_en = 'Average Expense Cost per Lost Time Claim', indicator_definition_en = 'The mean cost associated with each workplace injury claim that resulted in lost working time. Tracking this helps assess the financial impact of occupational health and safety incidents.' WHERE indicator_name = 'Kayıp zaman talebi başına ortalama gider maliyeti';
UPDATE indicators SET indicator_name_en = 'Percentage of Employees Wearing Prescribed PPE', indicator_definition_en = 'The share of employees who consistently use the prescribed personal protective equipment in required work areas. A fundamental compliance metric for workplace safety management.' WHERE indicator_name = 'Öngörülen KKD giyen çalışanların yüzdesi';
UPDATE indicators SET indicator_name_en = 'Total Number of Accidents', indicator_definition_en = 'The total count of workplace accidents recorded during a given period, regardless of severity. Tracking total accidents provides a baseline for safety trend analysis.' WHERE indicator_name = 'Toplam Kaza Sayısı';
UPDATE indicators SET indicator_name_en = 'Percentage of Personnel with Adequate OHS Training', indicator_definition_en = 'The share of employees who have completed all required occupational health and safety training. Adequate training coverage is essential for a safe workplace and regulatory compliance.' WHERE indicator_name = 'Yeterli İSG eğitimi almış personelin yüzdesi';

-- ============================================================
-- ADIM 3: 113 yeni KPI ekle (Türkçe + İngilizce)
-- ============================================================

INSERT INTO indicators (indicator_name, indicator_name_en, indicator_definition, indicator_definition_en, direction, measurement, related_process, is_default, is_accepted, is_deleted, is_confirm_deleted) VALUES

-- ARGE (10 yeni)
('Ar-Ge Harcamalarının Ciroya Oranı', 'R&D Spend as % of Revenue', 'Belirli bir dönemde toplam cirodan Ar-Ge faaliyetlerine ayrılan payın yüzdesi. Şirketin inovasyona olan bağlılığını ve rekabet edebilirlik kapasitesini ölçer.', 'The percentage of total revenue allocated to research and development activities in a given period. Reflects the organization''s commitment to innovation and long-term competitiveness.', 'Artması İyi', 'Yüzde', 'Arge', true, true, false, false),
('Yeni Ürün Geliştirme Döngü Süresi', 'New Product Development Cycle Time', 'Bir ürün fikrinin doğuşundan ticari lansmanına kadar geçen toplam süre. Kısa döngüler, organizasyonun pazara daha hızlı ürün sunabildiğini gösterir.', 'The total time elapsed from the initial concept of a product idea to its commercial launch. Shorter cycles indicate a more agile and competitive product development process.', 'Azalması İyi', 'Zaman', 'Arge', true, true, false, false),
('Ar-Ge Çalışanı Başına Patent Sayısı', 'Patents per R&D Employee', 'Belirli bir dönemde tescil edilen patent sayısının toplam Ar-Ge çalışanı sayısına oranı. Bireysel ve ekip bazında inovasyon üretkenliğini ölçer.', 'The number of patents filed or granted divided by the total number of R&D employees. Measures individual and team-level innovation productivity.', 'Artması İyi', 'Sayı', 'Arge', true, true, false, false),
('Başarılı Ürün Lansman Oranı', 'Successful Product Launch Rate', 'Lansmanı yapılan ürünler arasında hedeflenen satış ve müşteri kabul kriterlerini karşılayanların yüzdesi. Ürün geliştirme sürecinin pazar uyumu başarısını ölçer.', 'The percentage of launched products that meet predefined success criteria such as sales targets and customer adoption rates. Measures how well the product development pipeline aligns with market needs.', 'Artması İyi', 'Yüzde', 'Arge', true, true, false, false),
('Ar-Ge Proje Tamamlanma Oranı', 'R&D Project Completion Rate', 'Planlanan Ar-Ge projelerinden belirtilen süre ve bütçe içinde başarıyla tamamlananların yüzdesi. Proje yönetimi etkinliğini ve kaynak kullanımını değerlendirir.', 'The percentage of planned R&D projects completed on time and within budget. Evaluates project management effectiveness and resource allocation within the R&D function.', 'Artması İyi', 'Yüzde', 'Arge', true, true, false, false),
('İnovasyonun Ticarileştirme Oranı', 'Commercialization Rate of Innovations', 'Geliştirilen inovasyon fikirlerinden ticari ürün veya hizmete dönüştürülenlerin yüzdesi. Ar-Ge ile pazar arasındaki köprünün ne kadar etkin kurulduğunu gösterir.', 'The percentage of developed innovation ideas that are successfully converted into commercial products or services. Indicates how effectively the bridge between R&D and market is built.', 'Artması İyi', 'Yüzde', 'Arge', true, true, false, false),
('Ar-Ge Ekibi Personel Devir Oranı', 'R&D Team Turnover Rate', 'Belirli bir dönemde Ar-Ge ekibinden ayrılan çalışan sayısının toplam Ar-Ge kadrosuna oranı. Yüksek devir, kritik bilgi birikimi kaybına ve proje gecikmelerine yol açabilir.', 'The percentage of R&D staff who leave the organization in a given period relative to total R&D headcount. High turnover leads to knowledge loss and project delays.', 'Azalması İyi', 'Yüzde', 'Arge', true, true, false, false),
('Ürün Geliştirme Başarısızlık Oranı', 'Product Development Failure Rate', 'Başlatılan Ar-Ge projelerinden tamamlanamadan veya ticari hedeflerine ulaşamadan iptal edilenlerin yüzdesi. Süreç iyileştirme ve kaynak verimliliği için kritik bir göstergedir.', 'The percentage of initiated R&D projects that are cancelled or fail to meet commercial objectives. A critical metric for identifying process improvement opportunities and reducing resource waste.', 'Azalması İyi', 'Yüzde', 'Arge', true, true, false, false),
('Ar-Ge Çalışanı Başına Geliştirilen Ürün Sayısı', 'Products Developed per R&D Employee', 'Belirli bir dönemde geliştirilen ürün sayısının toplam Ar-Ge personeline oranı. Ar-Ge ekibinin üretkenliğini ve çıktı kapasitesini ölçer.', 'The number of products developed in a period divided by the total number of R&D staff. Measures the productivity and output capacity of the R&D team.', 'Artması İyi', 'Sayı', 'Arge', true, true, false, false),
('Ortalama Ürün Yaşam Döngüsü Süresi', 'Average Product Lifecycle Duration', 'Bir ürünün lansmanından pazardan çekilmesine kadar geçen ortalama süre. Uzun yaşam döngüleri güçlü pazar uyumunu ve sürdürülebilir rekabet avantajını gösterir.', 'The average time a product remains commercially available from launch to discontinuation. Longer lifecycles indicate strong market fit and sustained competitive advantage.', 'Artması İyi', 'Zaman', 'Arge', true, true, false, false),

-- BAKIM (9 yeni)
('Planlı Bakım Oranı', 'Planned Maintenance Ratio', 'Toplam bakım çalışma saatleri içinde planlı (önleyici) bakıma ayrılan saatlerin yüzdesi. Yüksek oran, reaktif yerine proaktif bir bakım kültürünü yansıtır.', 'The percentage of total maintenance hours dedicated to planned (preventive) maintenance activities. A higher ratio reflects a proactive maintenance culture over reactive break-fix approaches.', 'Artması İyi', 'Yüzde', 'Bakım', true, true, false, false),
('Bakım Maliyetinin Varlık Değerine Oranı', 'Maintenance Cost to Asset Value Ratio', 'Toplam bakım maliyetinin işletmedeki varlıkların kayıtlı değerine oranı. Oranın endüstri normlarıyla karşılaştırılması bakım yatırımının uygunluğunu değerlendirir.', 'The ratio of total maintenance costs to the total registered value of physical assets. Benchmarking against industry norms helps evaluate the appropriateness of maintenance investment levels.', 'Azalması İyi', 'Yüzde', 'Bakım', true, true, false, false),
('Acil Bakım Çalışma Süresi Oranı', 'Emergency Maintenance Work Hours Ratio', 'Toplam bakım çalışma saatleri içinde acil arıza onarımlarına harcanan saatlerin yüzdesi. Yüksek oran, önleyici bakım programlarının yetersizliğine işaret eder.', 'The percentage of total maintenance hours spent on emergency breakdown repairs. A high ratio signals inadequate preventive maintenance and a reactive maintenance posture.', 'Azalması İyi', 'Yüzde', 'Bakım', true, true, false, false),
('Ekipman Kullanılabilirlik Oranı', 'Equipment Availability Rate', 'Bir ekipmanın belirli bir süre içinde çalışmaya hazır ve kullanılabilir durumda olduğu sürenin toplam süreye oranı. Bakım programlarının etkinliğini doğrudan yansıtır.', 'The percentage of time that equipment is in an operable and available condition over a defined period. Directly reflects the effectiveness of maintenance programs and reliability efforts.', 'Artması İyi', 'Yüzde', 'Bakım', true, true, false, false),
('Yedek Parça Stok Devir Hızı', 'Spare Parts Inventory Turnover', 'Belirli bir dönemde yedek parça stoğunun kaç kez yenilendiğini gösteren oran. Yüksek devir hızı, stokta bağlanan sermayenin azalmasını ve daha verimli tedarik zinciri yönetimini gösterir.', 'The number of times spare parts inventory is consumed and replenished in a given period. Higher turnover rates indicate less capital tied up in stock and more efficient procurement.', 'Artması İyi', 'Sayı', 'Bakım', true, true, false, false),
('Önleyici Bakım Zamanında Tamamlanma Oranı', 'Preventive Maintenance Compliance Rate', 'Planlanan önleyici bakım görevlerinden zamanında ve eksiksiz tamamlananların yüzdesi. Bakım programlarına uyumu ve uzun vadeli ekipman güvenilirliğini ölçer.', 'The percentage of scheduled preventive maintenance tasks completed on time and in full. Measures adherence to maintenance programs and supports long-term equipment reliability.', 'Artması İyi', 'Yüzde', 'Bakım', true, true, false, false),
('Arıza Kaynaklı Duruş Süresi', 'Downtime Due to Equipment Failure', 'Ekipman arızaları nedeniyle üretim veya hizmetin durduğu toplam süre. Duruş sürelerinin azaltılması, üretim sürekliliği ve verimlilik için kritik öneme sahiptir.', 'The total time production or service is halted due to equipment failures. Reducing downtime is critical for maintaining production continuity and operational efficiency.', 'Azalması İyi', 'Zaman', 'Bakım', true, true, false, false),
('İş Emirlerinin Zamanında Kapatılma Oranı', 'On-Time Work Order Closure Rate', 'Açılan bakım iş emirlerinden hedeflenen süre içinde kapatılanların yüzdesi. Bakım ekibinin planlama ve yürütme disiplinini ölçer.', 'The percentage of maintenance work orders closed within the targeted timeframe. Measures the planning and execution discipline of the maintenance team.', 'Artması İyi', 'Yüzde', 'Bakım', true, true, false, false),
('Ortalama Arıza Maliyeti', 'Average Breakdown Cost', 'Her bir ekipman arızasının onarım işçiliği, yedek parça ve üretim kaybı dahil toplam maliyetinin ortalaması. Arıza maliyetlerinin izlenmesi bakım yatırım kararlarını destekler.', 'The average total cost of each equipment breakdown, including repair labor, spare parts, and production loss. Tracking breakdown costs supports data-driven maintenance investment decisions.', 'Azalması İyi', 'Para', 'Bakım', true, true, false, false),

-- BİLGİ TEKNOLOJİLERİ (11 yeni)
('Sistem Kullanılabilirlik Oranı (Uptime)', 'System Availability Rate (Uptime)', 'Kritik BT sistemlerinin planlı duruşlar dışında çalışır durumda olduğu zamanın toplam süreye oranı. Yüksek kullanılabilirlik, iş sürekliliği ve hizmet kalitesi için temel gerekliliktir.', 'The proportion of time critical IT systems remain operational, excluding planned maintenance windows. High availability is fundamental for business continuity and service quality.', 'Artması İyi', 'Yüzde', 'Bilgi Teknolojileri', true, true, false, false),
('Ortalama Olay Çözüm Süresi (IT MTTR)', 'Mean Time to Resolve IT Incidents', 'BT olaylarının raporlanmasından tam olarak çözülmesine kadar geçen ortalama süre. Kısa çözüm süreleri, etkili IT destek süreçleri ve nitelikli teknik personel varlığını gösterir.', 'The average time from reporting an IT incident to its complete resolution. Short resolution times indicate effective support processes and skilled technical staff.', 'Azalması İyi', 'Zaman', 'Bilgi Teknolojileri', true, true, false, false),
('Birinci Temas Çözüm Oranı', 'First Contact Resolution Rate', 'IT destek taleplerine ilk temas anında ek seviye veya eskalasyon gerektirmeksizin çözülen taleplerin yüzdesi. Yüksek oran, destek ekibinin yetkinliğini ve sorun çözme kapasitesini gösterir.', 'The percentage of IT support requests resolved at the first point of contact without escalation. High rates indicate a skilled support team with strong problem-solving capability.', 'Artması İyi', 'Yüzde', 'Bilgi Teknolojileri', true, true, false, false),
('BT Güvenlik Olayı Sayısı', 'Number of IT Security Incidents', 'Belirli bir dönemde tespit edilen siber güvenlik ihlali, veri sızıntısı veya yetkisiz erişim girişimi sayısı. Güvenlik olaylarının azaltılması, kurumsal varlıkların korunması açısından kritiktir.', 'The number of cybersecurity breaches, data leaks, or unauthorized access attempts detected in a period. Reducing security incidents is critical for protecting organizational assets and data.', 'Azalması İyi', 'Sayı', 'Bilgi Teknolojileri', true, true, false, false),
('Sprint Hızı (Yazılım Geliştirme)', 'Sprint Velocity', 'Bir çevik sprint döngüsünde tamamlanan iş miktarı (story points). Tutarlı veya artan sprint hızı, geliştirme ekibinin verimliliğini ve süreç olgunluğunu yansıtır.', 'The amount of work (story points) completed in an agile sprint cycle. Consistent or increasing velocity reflects development team productivity and process maturity.', 'Artması İyi', 'Sayı', 'Bilgi Teknolojileri', true, true, false, false),
('Yedekleme Başarı Oranı', 'Backup Success Rate', 'Kritik sistemler için planlanan yedekleme işlemlerinden başarıyla tamamlananların yüzdesi. Yüksek başarı oranı, veri kurtarma hazırlığı ve iş sürekliliği için temel bir gerekliliktir.', 'The percentage of scheduled backup operations completed successfully for critical systems. A high success rate is a foundational requirement for disaster recovery readiness.', 'Artması İyi', 'Yüzde', 'Bilgi Teknolojileri', true, true, false, false),
('Açık Güvenlik Açığı Sayısı', 'Open Security Vulnerabilities Count', 'Tespit edilmiş ancak henüz giderilmemiş güvenlik açığı sayısı. Açık güvenlik açıklarının minimize edilmesi, saldırı yüzeyinin daraltılması ve siber risk yönetimi açısından kritiktir.', 'The number of identified security vulnerabilities that have not yet been remediated. Minimizing open vulnerabilities reduces the attack surface and overall cyber risk posture.', 'Azalması İyi', 'Sayı', 'Bilgi Teknolojileri', true, true, false, false),
('BT Servis Masası Müşteri Memnuniyeti', 'IT Service Desk Customer Satisfaction Score', 'BT servis masası kullanıcılarının aldıkları hizmetten memnuniyetini ölçen anket puanı. Servis kalitesini ve son kullanıcı deneyimini değerlendiren temel bir BT KPI''ıdır.', 'A survey-based score measuring end-user satisfaction with IT service desk support. A key IT KPI for evaluating service quality and end-user experience.', 'Artması İyi', 'Puan', 'Bilgi Teknolojileri', true, true, false, false),
('Yazılım Test Kapsamı Oranı', 'Test Coverage Rate', 'Yazılım kaynak kodunun otomatik veya manuel testlerle kapsanan kısmının yüzdesi. Yüksek test kapsamı, üretim ortamına taşınan hata sayısını azaltır.', 'The percentage of software source code covered by automated or manual tests. Higher test coverage reduces the number of defects reaching the production environment.', 'Artması İyi', 'Yüzde', 'Bilgi Teknolojileri', true, true, false, false),
('Planlı Sistem Bakım Duruş Süresi', 'Planned System Maintenance Downtime', 'Yazılım güncellemeleri, altyapı bakımı veya yükseltmeler için planlanan sistem duruş sürelerinin toplamı. Duruşların minimize edilmesi ve iş dışı saatlere alınması kullanıcı deneyimini iyileştirir.', 'The total hours of planned system downtime scheduled for software updates, infrastructure maintenance, or upgrades. Minimizing downtime and scheduling it off-hours improves user experience.', 'Azalması İyi', 'Zaman', 'Bilgi Teknolojileri', true, true, false, false),
('Kullanıcı Başına BT Destek Maliyeti', 'IT Support Cost per User', 'Toplam BT destek maliyetinin aktif kullanıcı sayısına bölünmesiyle elde edilen ortalama maliyet. Kullanıcı başına düşen maliyetin izlenmesi, BT operasyonlarının verimliliğini değerlendirmeye yardımcı olur.', 'The total IT support cost divided by the number of active users. Monitoring cost per user helps benchmark IT operational efficiency and identify cost optimization opportunities.', 'Azalması İyi', 'Para', 'Bilgi Teknolojileri', true, true, false, false),

-- ÇEVRE (12 yeni)
('Toplam CO2 Salımı', 'Total CO2 Emissions', 'Organizasyonun tüm faaliyetlerinden kaynaklanan toplam karbondioksit eşdeğeri emisyon miktarı. İklim değişikliğiyle mücadelede temel çevresel performans göstergesidir.', 'The total amount of carbon dioxide equivalent emissions generated by all organizational activities. A fundamental environmental performance indicator in climate change mitigation efforts.', 'Azalması İyi', 'Ton', 'Çevre', true, true, false, false),
('Yenilenebilir Enerji Kullanım Oranı', 'Renewable Energy Usage Rate', 'Toplam enerji tüketimi içinde güneş, rüzgar gibi yenilenebilir kaynaklardan elde edilen enerjinin payı. Enerji dönüşümüne olan bağlılığı ve karbon ayak izini azaltma hedeflerini yansıtır.', 'The share of total energy consumption derived from renewable sources such as solar and wind. Reflects commitment to energy transition and carbon footprint reduction targets.', 'Artması İyi', 'Yüzde', 'Çevre', true, true, false, false),
('Toplam Atık Miktarı', 'Total Waste Generated', 'Organizasyonun faaliyetleri sonucunda üretilen toplam katı ve sıvı atık miktarı. Atık üretiminin azaltılması hem çevresel hem de ekonomik fayda sağlar.', 'The total amount of solid and liquid waste generated from organizational operations. Reducing waste generation delivers both environmental and economic benefits.', 'Azalması İyi', 'Ton', 'Çevre', true, true, false, false),
('Atık Geri Dönüşüm Oranı', 'Waste Recycling Rate', 'Toplam üretilen atık içinde geri dönüştürülen veya yeniden kullanıma kazandırılan atığın yüzdesi. Yüksek geri dönüşüm oranları döngüsel ekonomi ilkelerine uyumu gösterir.', 'The percentage of total waste generated that is recycled or recovered for reuse. High recycling rates demonstrate alignment with circular economy principles.', 'Artması İyi', 'Yüzde', 'Çevre', true, true, false, false),
('Toplam Su Tüketimi', 'Total Water Consumption', 'Organizasyonun üretim, temizlik ve idari faaliyetlerinde tükettiği toplam su hacmi. Su kıtlığının arttığı günümüzde su tüketiminin izlenmesi stratejik bir çevresel zorunluluktur.', 'The total volume of water consumed in production, cleaning, and administrative operations. Monitoring water use is a strategic environmental necessity as water scarcity increases globally.', 'Azalması İyi', 'Sayı', 'Çevre', true, true, false, false),
('Su Geri Dönüşüm Oranı', 'Water Recycling Rate', 'Toplam su tüketimi içinde arıtılıp yeniden kullanılan suyun yüzdesi. Su geri dönüşümü hem çevresel sürdürülebilirliğe katkı sağlar hem de su alım maliyetlerini azaltır.', 'The percentage of total water consumed that is treated and recycled for reuse. Water recycling contributes to environmental sustainability and reduces water procurement costs.', 'Artması İyi', 'Yüzde', 'Çevre', true, true, false, false),
('Üretim Birimi Başına Enerji Yoğunluğu', 'Energy Intensity per Production Unit', 'Bir birim ürün veya hizmet üretmek için harcanan toplam enerji miktarı. Enerji yoğunluğunun azaltılması verimliliği artırır ve karbon emisyonlarını düşürür.', 'The total energy consumed to produce one unit of product or service. Reducing energy intensity improves efficiency and lowers carbon emissions across the value chain.', 'Azalması İyi', 'Enerji', 'Çevre', true, true, false, false),
('Tehlikeli Atık Üretim Miktarı', 'Hazardous Waste Generation', 'Organizasyonun faaliyetlerinden kaynaklanan ve özel bertaraf gerektiren tehlikeli atık miktarı. Tehlikeli atıkların azaltılması yasal uyumluluk ve çevre güvenliği açısından kritiktir.', 'The amount of hazardous waste requiring special disposal generated from organizational operations. Reducing hazardous waste is critical for regulatory compliance and environmental safety.', 'Azalması İyi', 'Ton', 'Çevre', true, true, false, false),
('Çevre İhlali Sayısı', 'Number of Environmental Violations', 'Belirli bir dönemde çevre mevzuatı veya izin koşullarını ihlal eden olay sayısı. Sıfır ihlal hedefi kurumsal çevre yönetiminin etkinliğini ve yasal uyumunu gösterir.', 'The count of incidents violating environmental regulations or permit conditions in a given period. A zero-violation target demonstrates effective environmental management and regulatory compliance.', 'Azalması İyi', 'Sayı', 'Çevre', true, true, false, false),
('Karbon Nötr Proje Sayısı', 'Number of Carbon Neutral Projects', 'Sıfır net karbon salımı hedefiyle yürütülen veya tamamlanan proje sayısı. İklim taahhütlerine yönelik somut adımları ve kurumsal sürdürülebilirlik dönüşümünü yansıtır.', 'The number of projects designed or completed with a net-zero carbon emission goal. Reflects tangible progress toward climate commitments and the corporate sustainability transformation.', 'Artması İyi', 'Sayı', 'Çevre', true, true, false, false),
('Çevre Sertifikasyon Uyumluluk Oranı', 'Environmental Certification Compliance Rate', 'ISO 14001 gibi çevre yönetim sistemi sertifikasyonlarının gerekliliklerine uyum sağlanan süreçlerin yüzdesi. Kurumsal çevre yönetiminin olgunluk düzeyini gösterir.', 'The percentage of processes compliant with environmental management system certification requirements such as ISO 14001. Indicates the maturity level of the organization''s environmental management.', 'Artması İyi', 'Yüzde', 'Çevre', true, true, false, false),
('Sera Gazı Emisyon Yoğunluğu', 'Greenhouse Gas Emission Intensity', 'Belirli bir üretim veya gelir birimi başına düşen toplam sera gazı emisyonu miktarı. Mutlak emisyon değerinden bağımsız olarak organizasyonun iklim verimliliğini karşılaştırmalı olarak ölçer.', 'The total greenhouse gas emissions per unit of production or revenue. Measures the organization''s climate efficiency independent of absolute scale, enabling meaningful benchmarking.', 'Azalması İyi', 'Ton', 'Çevre', true, true, false, false),

-- FİNANS (5 yeni)
('Net Kar Marjı', 'Net Profit Margin', 'Toplam gelirin vergiler ve tüm giderler düşüldükten sonra kalan net karın gelire oranı. Şirketin genel karlılığını ve maliyet yönetiminin etkinliğini gösteren temel finansal bir göstergedir.', 'The ratio of net profit after all expenses and taxes to total revenue. A fundamental financial metric reflecting the company''s overall profitability and cost management effectiveness.', 'Artması İyi', 'Yüzde', 'Finans', true, true, false, false),
('Cari Oran', 'Current Ratio', 'Dönen varlıkların kısa vadeli borçlara oranı. 1''in üzerindeki değerler şirketin kısa vadeli yükümlülüklerini karşılayacak likit varlığa sahip olduğunu gösterir.', 'The ratio of current assets to current liabilities. Values above 1 indicate the company has sufficient liquid assets to meet short-term obligations.', 'Artması İyi', 'Sayı', 'Finans', true, true, false, false),
('Özkaynak Karlılığı (ROE)', 'Return on Equity (ROE)', 'Net karın özkaynak toplamına oranı. Hissedarların yatırımı üzerinden elde edilen getiriyi ölçer ve sermaye kullanım etkinliğinin en önemli göstergelerinden biridir.', 'The ratio of net profit to total shareholders'' equity. Measures the return generated on shareholders'' investment and is one of the most important indicators of capital efficiency.', 'Artması İyi', 'Yüzde', 'Finans', true, true, false, false),
('Varlık Devir Hızı', 'Asset Turnover Ratio', 'Toplam gelirin ortalama toplam varlıklara oranı. Şirketin varlıklarını ne kadar verimli kullanarak gelir ürettiğini gösterir; düşük oran varlık yönetiminde verimsizliğe işaret edebilir.', 'The ratio of total revenue to average total assets. Shows how efficiently the company uses its asset base to generate revenue; a low ratio may signal inefficiency in asset management.', 'Artması İyi', 'Sayı', 'Finans', true, true, false, false),
('Borç/Özkaynak Oranı', 'Debt-to-Equity Ratio', 'Toplam borcun özkaynak toplamına oranı. Şirketin finansal kaldıraç düzeyini ve finansal riskini ölçer; yüksek oran artan borç yükünü ve finansal kırılganlığı işaret eder.', 'The ratio of total debt to total shareholders'' equity. Measures the company''s financial leverage and risk; a high ratio indicates greater debt burden and financial vulnerability.', 'Azalması İyi', 'Sayı', 'Finans', true, true, false, false),

-- İNSAN KAYNAKLARI (11 yeni)
('Çalışan Bağlılık Endeksi', 'Employee Engagement Index', 'Çalışanların işlerine, ekiplerine ve organizasyona olan duygusal bağlılık düzeyini ölçen anket temelli bileşik skor. Yüksek bağlılık düşük devir, yüksek verimlilik ve güçlü kurumsal kültürle ilişkilidir.', 'A survey-based composite score measuring employees'' emotional commitment to their work, team, and organization. High engagement correlates with lower turnover, higher productivity, and a strong culture.', 'Artması İyi', 'Puan', 'İnsan Kaynakları', true, true, false, false),
('Çalışan Başına Eğitim Maliyeti', 'Training Cost per Employee', 'Belirli bir dönemde çalışan başına düşen toplam eğitim ve gelişim harcaması. Bu maliyetin izlenmesi insan kaynağına yapılan yatırımın etkinliğini değerlendirmeye yardımcı olur.', 'The total training and development expenditure per employee in a given period. Tracking this cost helps evaluate the return on investment in human capital development.', 'Azalması İyi', 'Para', 'İnsan Kaynakları', true, true, false, false),
('Eğitim Memnuniyeti Oranı', 'Training Satisfaction Rate', 'Eğitim programlarına katılan çalışanların programdan memnuniyetini ifade eden yüzde. Yüksek memnuniyet oranı, eğitim içeriklerinin ve yöntemlerinin çalışan ihtiyaçlarını karşıladığını gösterir.', 'The percentage of employees reporting satisfaction with the training programs they attended. High satisfaction indicates that training content and methods effectively meet employee development needs.', 'Artması İyi', 'Yüzde', 'İnsan Kaynakları', true, true, false, false),
('Açık Pozisyon Doldurma Süresi', 'Time to Fill Open Positions', 'Bir pozisyonun açılmasından uygun adayla doldurulmasına kadar geçen ortalama süre. Uzun süreçler operasyonel aksaklıklara yol açarken kısa süreçler etkin işe alım kapasitesini gösterir.', 'The average time from a position opening to it being filled with a suitable candidate. Long times cause operational disruptions while short times indicate effective recruitment capacity.', 'Azalması İyi', 'Zaman', 'İnsan Kaynakları', true, true, false, false),
('Gönüllü İşten Ayrılma Oranı', 'Voluntary Turnover Rate', 'Belirli bir dönemde çalışanların kendi isteğiyle işten ayrılma oranı. Yüksek gönüllü ayrılma, çalışan memnuniyeti, maaş rekabetçiliği veya kariyer fırsatlarında sorunlara işaret edebilir.', 'The percentage of employees who voluntarily resign in a given period. High voluntary turnover may signal issues with employee satisfaction, competitive compensation, or career growth opportunities.', 'Azalması İyi', 'Yüzde', 'İnsan Kaynakları', true, true, false, false),
('İç Terfi Oranı', 'Internal Promotion Rate', 'Belirli bir dönemde üst pozisyonlara yapılan atamaların iç adaylarla doldurulma yüzdesi. Yüksek iç terfi oranı güçlü yetenek geliştirme programlarını ve kariyer yollarını yansıtır.', 'The percentage of senior position appointments filled by internal candidates in a given period. A high internal promotion rate reflects strong talent development programs and career pathways.', 'Artması İyi', 'Yüzde', 'İnsan Kaynakları', true, true, false, false),
('Çalışan Üretkenlik Endeksi', 'Employee Productivity Index', 'Bir çalışanın belirli bir sürede ürettiği değerin veya çıktının ölçüldüğü bileşik skor. Verimlilik endeksinin izlenmesi iş gücü optimizasyon kararlarını ve eğitim önceliklerini destekler.', 'A composite score measuring the value or output produced by an employee over a defined period. Monitoring the productivity index supports workforce optimization and training prioritization decisions.', 'Artması İyi', 'Puan', 'İnsan Kaynakları', true, true, false, false),
('İşe Alım Başına Maliyet', 'Cost per Hire', 'Bir yeni çalışanı işe almak için harcanan toplam maliyet; reklam, ajans, mülakat ve oryantasyon giderlerini kapsar. Bu maliyetin optimize edilmesi işe alım süreçlerinin verimliliğini artırır.', 'The total cost to hire one new employee, including advertising, agency fees, interview, and onboarding expenses. Optimizing this cost improves the efficiency of the recruitment function.', 'Azalması İyi', 'Para', 'İnsan Kaynakları', true, true, false, false),
('Yönetici Etkinlik Skoru', 'Manager Effectiveness Score', 'Yöneticilerin liderlik, iletişim ve ekip geliştirme becerilerini değerlendiren 360 derece geri bildirim temelli skor. Yüksek skor, yöneticilerin ekip performansını ve bağlılığını olumlu yönde etkilediğini gösterir.', 'A 360-degree feedback-based score evaluating managers on leadership, communication, and team development. A high score indicates that managers positively impact team performance and engagement.', 'Artması İyi', 'Puan', 'İnsan Kaynakları', true, true, false, false),
('Çalışan Başına Eğitim Saati', 'Training Hours per Employee', 'Belirli bir dönemde bir çalışanın aldığı toplam resmi eğitim süresi. Yeterli eğitim saati, çalışanların beceri gelişimini destekler ve organizasyonun yetkinlik düzeyini yükseltir.', 'The total formal training hours received per employee in a given period. Adequate training hours support skill development and raise the overall competency level of the organization.', 'Artması İyi', 'Zaman', 'İnsan Kaynakları', true, true, false, false),
('İş Gücü Devamsızlık Oranı', 'Workforce Absenteeism Rate', 'Toplam planlı çalışma saatleri içinde çalışanların devamsızlık nedeniyle kaybedilen saat oranı. Yüksek devamsızlık oranları çalışan sağlığı, motivasyonu veya işyeri koşullarına ilişkin sorunlara işaret edebilir.', 'The proportion of total planned working hours lost due to employee absences. High absenteeism rates may signal issues related to employee health, motivation, or workplace conditions.', 'Azalması İyi', 'Yüzde', 'İnsan Kaynakları', true, true, false, false),

-- İŞ SAĞLIĞI VE GÜVENLİĞİ (10 yeni)
('Kaza Başına Ortalama İyileşme Süresi', 'Average Recovery Time per Accident', 'Çalışanların iş kazası sonrasında tam çalışma kapasitesine dönmesi için geçen ortalama süre. Kısa iyileşme süreleri, tıbbi destek ve iş uyum programlarının etkinliğini yansıtır.', 'The average time for employees to return to full working capacity after a workplace accident. Short recovery times reflect the effectiveness of medical support and workplace rehabilitation programs.', 'Azalması İyi', 'Zaman', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('Güvenlik Eğitimi Uyum Oranı', 'Safety Training Compliance Rate', 'Zorunlu güvenlik eğitimlerini zamanında tamamlayan çalışan yüzdesi. Yüksek uyum oranı, yasal yükümlülüklerin yerine getirilmesini ve çalışan güvenliğine kurumsal bağlılığı gösterir.', 'The percentage of employees who complete mandatory safety training on time. A high compliance rate demonstrates fulfillment of legal obligations and organizational commitment to employee safety.', 'Artması İyi', 'Yüzde', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('Güvenlik Denetimi Uygunsuzluk Oranı', 'Safety Audit Non-Conformance Rate', 'Güvenlik denetimlerinde tespit edilen uygunsuzlukların toplam denetim bulgusuna oranı. Yüksek oran, güvenlik prosedürlerine uyumda sistematik açıklar bulunduğuna işaret eder.', 'The proportion of non-conformances identified in safety audits relative to total audit findings. A high rate signals systematic gaps in safety procedure compliance.', 'Azalması İyi', 'Yüzde', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('Ramak Kala Olay Raporlama Oranı', 'Near Miss Reporting Rate', 'Kaza ile sonuçlanmadan önce bildirilen ramak kala olay sayısının toplam olası olay sayısına oranı. Yüksek raporlama oranı, proaktif güvenlik kültürü ve şeffaf iletişimi gösterir.', 'The proportion of near-miss incidents reported before resulting in actual accidents. A high reporting rate indicates a proactive safety culture and transparent communication.', 'Artması İyi', 'Yüzde', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('İş Kazası Toplam Maliyeti', 'Total Cost of Work Accidents', 'İş kazaları nedeniyle oluşan tazminat, sağlık, kayıp üretim ve idari giderler dahil toplam maliyet. Bu maliyetin izlenmesi güvenlik yatırımlarının ekonomik gerekçesini güçlendirir.', 'The total cost of workplace accidents including compensation, healthcare, lost production, and administrative expenses. Monitoring this cost strengthens the economic justification for safety investments.', 'Azalması İyi', 'Para', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('Güvenlik İyileştirme Girişimi Sayısı', 'Number of Safety Improvement Initiatives', 'Belirli bir dönemde hayata geçirilen proaktif güvenlik iyileştirme ve önlem projesi sayısı. Yüksek sayı, organizasyonun güvenliği sürekli iyileştirme anlayışıyla ele aldığını gösterir.', 'The number of proactive safety improvement projects or measures implemented in a given period. A high count indicates the organization is actively pursuing continuous safety improvement.', 'Artması İyi', 'Sayı', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('Güvenlik Prosedürü Uyum Oranı', 'Safety Procedure Compliance Rate', 'Çalışanların yazılı güvenlik prosedür ve talimatlarına uyum gösterdiği denetim gözlemlerinin yüzdesi. Yüksek uyum, güvenlik prosedürlerinin etkin biçimde uygulandığını ve benimsediğini gösterir.', 'The percentage of audit observations showing employees following written safety procedures and instructions. High compliance demonstrates effective implementation and internalization of safety procedures.', 'Artması İyi', 'Yüzde', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('Ramak Kala Olay Sayısı', 'Number of Near Misses', 'Yaralanma veya hasara yol açmadan önce durdurulan tehlikeli olay sayısı. Ramak kala olayların raporlanması ve analizi ciddi kazaların önlenmesinde kritik rol oynar.', 'The count of hazardous incidents stopped before causing injury or damage. Reporting and analyzing near misses plays a critical role in preventing serious accidents.', 'Azalması İyi', 'Sayı', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('İSG Sertifikasyon Oranı', 'OHS Certification Rate', 'İş sağlığı ve güvenliği alanında geçerli sertifikaya sahip çalışan ve yönetici yüzdesi. Sertifikasyon oranının yüksek tutulması, kurumsal ISG yetkinliğini ve yasal uyumu destekler.', 'The percentage of employees and managers holding valid occupational health and safety certifications. Maintaining a high certification rate supports organizational OHS competence and legal compliance.', 'Artması İyi', 'Yüzde', 'İş Sağlığı ve Güvenliği', true, true, false, false),
('Risk Değerlendirmesi Tamamlanma Oranı', 'Risk Assessment Completion Rate', 'Belirlenen tüm iş süreçleri ve çalışma alanlarında risk değerlendirmesinin tamamlanma yüzdesi. Kapsamlı risk değerlendirmesi, iş güvenliği yönetim sisteminin temel bileşenidir.', 'The percentage of identified work processes and areas for which risk assessments have been completed. Comprehensive risk assessment is a foundational component of the occupational safety management system.', 'Artması İyi', 'Yüzde', 'İş Sağlığı ve Güvenliği', true, true, false, false),

-- KALİTE (13 yeni)
('İlk Geçişte Kalite Oranı (FPY)', 'First Pass Yield (FPY)', 'Üretim hattında ilk geçişte herhangi bir yeniden işlem veya düzeltme gerektirmeksizin kalite standartlarını karşılayan ürün yüzdesi. Süreç kalitesinin en doğrudan ölçüm araçlarından biridir.', 'The percentage of units produced that meet quality standards on the first pass without any rework or correction. One of the most direct measures of process quality.', 'Artması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Hata Oranı', 'Defect Rate', 'Belirli bir üretim döneminde toplam birim içinde kalite standartlarını karşılamayan hatalı birim yüzdesi. Hata oranının düşürülmesi müşteri memnuniyetini artırır ve yeniden işlem maliyetlerini azaltır.', 'The percentage of units produced that fail to meet quality standards in a given production period. Reducing the defect rate improves customer satisfaction and lowers rework costs.', 'Azalması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Ürün Geri Çağırma Sayısı', 'Product Recall Count', 'Kalite veya güvenlik sorunları nedeniyle piyasadan geri çağrılan ürün sayısı. Ürün geri çağırmaları hem ciddi finansal kayıplara hem de marka itibarının zedelenmesine yol açar.', 'The number of products recalled from the market due to quality or safety issues. Product recalls cause significant financial losses and damage brand reputation.', 'Azalması İyi', 'Sayı', 'Kalite', true, true, false, false),
('Kalite Maliyeti Oranı', 'Cost of Quality Ratio', 'Hata önleme, değerlendirme ve hata giderme maliyetlerinin toplam üretim maliyetine oranı. Düşük kalite maliyeti oranı, yüksek kalite güvencesi ve verimli süreçleri yansıtır.', 'The ratio of prevention, appraisal, and failure costs to total production costs. A low cost of quality ratio reflects high quality assurance and efficient processes.', 'Azalması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Garanti Talebi Oranı', 'Warranty Claim Rate', 'Satılan ürünler içinde garanti kapsamında talep oluşturanların yüzdesi. Yüksek garanti talebi oranı, ürün tasarımı veya üretim kalitesinde köklü sorunlara işaret edebilir.', 'The percentage of sold products for which a warranty claim is made. A high warranty claim rate may signal fundamental issues in product design or manufacturing quality.', 'Azalması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Tedarikçi Kalite Ret Oranı', 'Supplier Quality Rejection Rate', 'Gelen tedarikçi malzemelerinden kalite kontrolden geçemeyen miktarın yüzdesi. Yüksek ret oranı tedarikçi yönetimi ve tedarik zinciri kalitesine odaklanılması gerektiğini gösterir.', 'The percentage of incoming supplier materials that fail quality inspection. A high rejection rate signals the need to focus on supplier management and supply chain quality.', 'Azalması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Düzeltici Faaliyet Tamamlanma Oranı', 'Corrective Action Completion Rate', 'Tanımlanan kalite sorunları için açılan düzeltici faaliyetlerin hedeflenen süre içinde tamamlanma yüzdesi. Zamanında tamamlama, kalite sorunlarının tekrarlamasını engeller.', 'The percentage of corrective actions opened for identified quality issues completed within the target timeframe. Timely completion prevents the recurrence of quality problems.', 'Artması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Belge Güncelleme Uyum Oranı', 'Document Update Compliance Rate', 'Revizyon tarihi geçmiş veya güncellemesi gereken kalite belgelerinin zamanında güncelleme oranı. Kalite yönetim sistemi belgelerinin güncelliği, standardizasyon ve denetim hazırlığı için kritiktir.', 'The rate at which quality documents requiring revision are updated on time. Keeping QMS documents current is critical for standardization and audit readiness.', 'Artması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Müşteri İade Oranı', 'Customer Return Rate', 'Satılan ürünlerin kalite veya uyumsuzluk nedeniyle müşteri tarafından iade edilme yüzdesi. Yüksek iade oranı müşteri memnuniyetsizliğini ve ürün kalite sorunlarını işaret eder.', 'The percentage of sold products returned by customers due to quality or non-conformance issues. A high return rate signals customer dissatisfaction and product quality problems.', 'Azalması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Süreç Yeterlilik Endeksi (Cpk)', 'Process Capability Index (Cpk)', 'Bir üretim sürecinin belirtilen tolerans sınırları içinde ürün üretme yeteneğini gösteren istatistiksel ölçüt. Cpk değerinin 1,33''ün üzerinde olması yeterli süreç kapasitesinin göstergesidir.', 'A statistical measure of a manufacturing process''s ability to produce output within specified tolerance limits. A Cpk value above 1.33 is generally considered indicative of a capable process.', 'Artması İyi', 'Sayı', 'Kalite', true, true, false, false),
('Dış Denetim Uygunsuzluk Sayısı', 'External Audit Non-Conformance Count', 'Dış denetçiler tarafından tespit edilen major ve minör uygunsuzlukların toplam sayısı. Düşük sayı, kalite yönetim sisteminin sağlam ve standartlara uyumlu olduğunu gösterir.', 'The total number of major and minor non-conformances identified by external auditors. A low count indicates that the quality management system is robust and standards-compliant.', 'Azalması İyi', 'Sayı', 'Kalite', true, true, false, false),
('Kalite İyileştirme Projesi Tamamlanma Oranı', 'Quality Improvement Project Completion Rate', 'Planlanan kalite iyileştirme projelerinden hedef tarihte tamamlananların yüzdesi. Bu oran kurumun sürekli iyileştirme kültürünü benimseme düzeyini yansıtır.', 'The percentage of planned quality improvement projects completed by their target date. This rate reflects the organization''s level of commitment to a continuous improvement culture.', 'Artması İyi', 'Yüzde', 'Kalite', true, true, false, false),
('Kalite Maliyeti Tasarrufu', 'Quality Cost Savings', 'Kalite iyileştirme girişimleri sonucunda hata giderme, yeniden işlem ve garanti maliyetlerinde elde edilen toplam tasarruf. Kaliteye yapılan yatırımın finansal getirisini ölçer.', 'The total savings achieved in failure, rework, and warranty costs as a result of quality improvement initiatives. Measures the financial return on quality investments.', 'Artması İyi', 'Para', 'Kalite', true, true, false, false),

-- SATIŞ VE PAZARLAMA (5 yeni)
('Müşteri Yaşam Boyu Değeri (CLV)', 'Customer Lifetime Value (CLV)', 'Bir müşterinin organizasyonla ilişkisi süresince sağladığı toplam net gelir. Müşteri edinim kararlarını ve sadakat yatırımlarını yönlendiren en stratejik pazarlama metriklerinden biridir.', 'The total net revenue a customer is expected to generate throughout their relationship with the organization. One of the most strategic marketing metrics guiding acquisition and loyalty investment decisions.', 'Artması İyi', 'Para', 'Satış ve Pazarlama', true, true, false, false),
('Müşteri Edinim Maliyeti (CAC)', 'Customer Acquisition Cost (CAC)', 'Yeni bir müşteri kazanmak için harcanan toplam pazarlama ve satış maliyetinin edinilen müşteri sayısına oranı. CLV/CAC oranı, büyüme stratejisinin sürdürülebilirliğini değerlendirmek için kritiktir.', 'The total marketing and sales cost divided by the number of new customers acquired. The CLV/CAC ratio is critical for evaluating the sustainability of the growth strategy.', 'Azalması İyi', 'Para', 'Satış ve Pazarlama', true, true, false, false),
('Net Tavsiye Skoru (NPS)', 'Net Promoter Score (NPS)', 'Müşterilerin organizasyonu başkalarına tavsiye etme olasılığını ölçen -100 ile +100 arasında değer alan skor. Müşteri sadakatinin ve olumlu ağızdan ağıza yayılmanın en yaygın ölçütüdür.', 'A score ranging from -100 to +100 measuring the likelihood of customers recommending the organization to others. The most widely used measure of customer loyalty and positive word-of-mouth.', 'Artması İyi', 'Puan', 'Satış ve Pazarlama', true, true, false, false),
('Dijital Kanal Dönüşüm Oranı', 'Digital Channel Conversion Rate', 'Dijital pazarlama kanalları aracılığıyla web sitesi ziyaretçilerinin veya uygulama kullanıcılarının satın alma gerçekleştirme yüzdesi. Dijital pazarlama yatırımlarının etkinliğini doğrudan yansıtır.', 'The percentage of website visitors or app users acquired through digital marketing channels who complete a purchase. Directly reflects the effectiveness of digital marketing investments.', 'Artması İyi', 'Yüzde', 'Satış ve Pazarlama', true, true, false, false),
('Ortalama Satış Döngüsü Süresi', 'Average Sales Cycle Length', 'İlk müşteri temasından sözleşme imzalanmasına kadar geçen ortalama süre. Kısa satış döngüleri, satış sürecinin etkinliğini artırır ve gelir tahminlerinin tutarlılığını yükseltir.', 'The average time from first customer contact to contract signing. Shorter sales cycles improve sales process efficiency and increase the reliability of revenue forecasting.', 'Azalması İyi', 'Zaman', 'Satış ve Pazarlama', true, true, false, false),

-- TEDARİK ZİNCİRİ (14 yeni)
('Tedarikçi Zamanında Teslimat Oranı', 'Supplier On-Time Delivery Rate', 'Tedarikçilerden gelen siparişlerin taahhüt edilen tarihte eksiksiz teslim edilme yüzdesi. Tedarik zinciri güvenilirliğini ve tedarikçi performansını değerlendiren temel bir KPI''dır.', 'The percentage of supplier orders delivered completely on the committed date. A key KPI for evaluating supply chain reliability and supplier performance.', 'Artması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Stok Devir Hızı', 'Inventory Turnover Rate', 'Belirli bir dönemde stokların kaç kez tamamen yenilendiğini gösteren oran. Yüksek devir hızı stokta bağlanan sermayenin azalmasını ve verimli stok yönetimini gösterir.', 'The number of times total inventory is sold and replaced over a given period. High turnover indicates less capital tied up in stock and more efficient inventory management.', 'Artması İyi', 'Sayı', 'Tedarik Zinciri', true, true, false, false),
('Tedarik Teslim Süresi', 'Procurement Lead Time', 'Satınalma talebinden malzemenin teslim alınmasına kadar geçen ortalama süre. Kısa tedarik süreleri üretim sürekliliğini destekler ve stok tamponu ihtiyacını azaltır.', 'The average time from purchase request to receipt of materials. Short lead times support production continuity and reduce the need for safety stock buffers.', 'Azalması İyi', 'Zaman', 'Tedarik Zinciri', true, true, false, false),
('Tedarikçi Hata Oranı', 'Supplier Defect Rate', 'Gelen tedarikçi malzemeleri içinde kalite kontrolden geçemeyen hatalı malzeme yüzdesi. Yüksek tedarikçi hata oranı üretim kalitesini ve süreç verimliliğini olumsuz etkiler.', 'The percentage of incoming supplier materials that fail quality inspection. A high supplier defect rate negatively impacts production quality and process efficiency.', 'Azalması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Depo Doluluk Oranı', 'Warehouse Utilization Rate', 'Kullanılabilir toplam depo alanının aktif olarak kullanılan yüzdesi. Optimum doluluk oranı depo maliyetlerini minimize ederken stok erişilebilirliğini korur.', 'The percentage of total available warehouse space actively utilized. Optimal utilization minimizes warehousing costs while maintaining stock accessibility.', 'Artması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Mükemmel Sipariş Oranı', 'Perfect Order Rate', 'Doğru ürün, doğru miktar, doğru zamanda, doğru yere ve hasarsız teslim edilen siparişlerin toplam siparişe oranı. Tedarik zinciri mükemmelliğinin en kapsamlı ölçütlerinden biridir.', 'The proportion of orders delivered with the right product, quantity, time, location, and condition with no damage. One of the most comprehensive measures of supply chain excellence.', 'Artması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Stok Kesintisi Oranı', 'Stockout Rate', 'Belirli bir dönemde müşteri talebinin karşılanamadığı stok dışı durumların oranı. Yüksek stok kesintisi oranı gelir kaybına ve müşteri kaybına yol açar.', 'The proportion of periods in which customer demand cannot be met due to stock unavailability. A high stockout rate leads to revenue loss and customer churn.', 'Azalması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Tedarikçi Değerlendirme Skoru', 'Supplier Evaluation Score', 'Tedarikçilerin kalite, teslimat, fiyat ve hizmet kriterlerine göre değerlendirildiği bileşik performans skoru. Tedarikçi geliştirme ve seçim kararlarına temel oluşturur.', 'A composite performance score evaluating suppliers on quality, delivery, price, and service criteria. Forms the basis for supplier development and selection decisions.', 'Artması İyi', 'Puan', 'Tedarik Zinciri', true, true, false, false),
('Satınalma Siparişi Zamanında Tamamlanma Oranı', 'Purchase Order On-Time Completion Rate', 'Satınalma siparişlerinin taahhüt edilen teslimat tarihine kadar eksiksiz tamamlanma yüzdesi. Tedarik zinciri güvenilirliğini ve satınalma sürecinin etkinliğini ölçer.', 'The percentage of purchase orders completed in full by the committed delivery date. Measures supply chain reliability and procurement process effectiveness.', 'Artması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Lojistik Maliyetinin Ciroya Oranı', 'Logistics Cost as % of Revenue', 'Toplam lojistik ve dağıtım maliyetlerinin şirket cirosuna oranı. Bu oranın sektör benchmarklarıyla karşılaştırılması lojistik verimliliğini değerlendirmeye yardımcı olur.', 'The ratio of total logistics and distribution costs to company revenue. Benchmarking this ratio against industry standards helps evaluate logistics efficiency.', 'Azalması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Depo Hata Oranı', 'Warehouse Error Rate', 'Toplam depo işlemleri içinde hatalı yerleştirme, yanlış sipariş toplama veya eksik sevkiyat gibi hataların yüzdesi. Hata oranının düşürülmesi müşteri memnuniyetini artırır.', 'The percentage of total warehouse operations resulting in errors such as mis-stocking, wrong picking, or incomplete shipments. Reducing error rates improves customer satisfaction.', 'Azalması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Kargo Hasar Oranı', 'Cargo Damage Rate', 'Taşıma sürecinde hasar gören kargo miktarının toplam sevk edilen kargoya oranı. Düşük hasar oranı, paketleme kalitesi ve taşıma yönetiminin etkinliğini gösterir.', 'The proportion of cargo damaged during transportation relative to total shipments. A low damage rate indicates good packaging quality and effective transportation management.', 'Azalması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Tedarikçi Çeşitlendirme Oranı', 'Supplier Diversification Rate', 'Kritik malzeme veya hizmetlerin tek bir tedarikçiye bağımlılık riskini azaltmak amacıyla birden fazla tedarikçiden temin edilme oranı. Yüksek çeşitlendirme tedarik zinciri direncini artırır.', 'The proportion of critical materials or services sourced from multiple suppliers to reduce single-source dependency risk. Higher diversification increases supply chain resilience.', 'Artması İyi', 'Yüzde', 'Tedarik Zinciri', true, true, false, false),
('Ortalama Sipariş Karşılama Süresi', 'Average Order Fulfillment Time', 'Müşteri siparişinin alınmasından teslimatın tamamlanmasına kadar geçen ortalama süre. Kısa karşılama süreleri müşteri memnuniyetini artırır ve rekabetçi üstünlük sağlar.', 'The average time from receiving a customer order to completing its delivery. Short fulfillment times improve customer satisfaction and provide a competitive advantage.', 'Azalması İyi', 'Zaman', 'Tedarik Zinciri', true, true, false, false),

-- ÜRETİM (11 yeni)
('Çevrim Süresi', 'Cycle Time', 'Bir üretim sürecinde tek bir birimin tamamlanması için gereken toplam süre. Çevrim süresinin azaltılması üretim kapasitesini artırır ve teslimat sürelerini kısaltır.', 'The total time required to complete one unit through a production process. Reducing cycle time increases production capacity and shortens delivery lead times.', 'Azalması İyi', 'Zaman', 'Üretim', true, true, false, false),
('Üretim Verimliliği', 'Production Efficiency Rate', 'Gerçek üretim çıktısının standart veya hedeflenen çıktıya oranı. Yüksek verimlilik, kaynakların ve süreçlerin optimum düzeyde kullanıldığını gösterir.', 'The ratio of actual production output to standard or targeted output. High efficiency indicates that resources and processes are being used optimally.', 'Artması İyi', 'Yüzde', 'Üretim', true, true, false, false),
('Hurda Oranı', 'Scrap Rate', 'Üretim sürecinde yeniden işlenemeyip hurda olarak atılan malzeme veya ürün yüzdesi. Hurda oranının düşürülmesi hammadde maliyetlerini azaltır ve sürdürülebilirliği artırır.', 'The percentage of material or products that cannot be reworked and are discarded as scrap. Reducing scrap rates lowers raw material costs and improves sustainability.', 'Azalması İyi', 'Yüzde', 'Üretim', true, true, false, false),
('Yeniden İşleme Oranı', 'Rework Rate', 'Kalite standartlarını karşılamayan ve düzeltme amacıyla yeniden işleme alınan ürün yüzdesi. Yüksek yeniden işleme oranı iş gücü ve zaman kaybına yol açarak üretim verimliliğini düşürür.', 'The percentage of products that fail to meet quality standards and must be reprocessed for correction. High rework rates cause labor and time losses, reducing overall production efficiency.', 'Azalması İyi', 'Yüzde', 'Üretim', true, true, false, false),
('Makine Duruş Süresi Oranı', 'Machine Downtime Rate', 'Toplam planlı üretim süresi içinde makinenin arıza veya beklenmedik duruşlar nedeniyle çalışmadığı sürenin yüzdesi. Duruş oranının minimize edilmesi üretim kapasitesini korur.', 'The percentage of total planned production time during which machines are not running due to breakdowns or unexpected stoppages. Minimizing downtime rates preserves production capacity.', 'Azalması İyi', 'Yüzde', 'Üretim', true, true, false, false),
('Üretim Planına Uyum Oranı', 'Production Schedule Adherence', 'Haftalık veya aylık üretim planında belirlenen hedeflerin fiilen tamamlanma yüzdesi. Yüksek plan uyumu, üretim süreçlerinin öngörülebilirliğini ve müşteri teslimat güvenilirliğini artırır.', 'The percentage of production targets in the weekly or monthly plan actually completed. High schedule adherence improves production predictability and customer delivery reliability.', 'Artması İyi', 'Yüzde', 'Üretim', true, true, false, false),
('Birim Başına Üretim Maliyeti', 'Production Cost per Unit', 'Bir birim ürün üretmek için harcanan toplam maliyetin (işçilik, malzeme, genel giderler) ortalaması. Birim maliyetin izlenmesi fiyatlandırma kararlarını ve maliyet optimizasyonunu destekler.', 'The average total cost (labor, materials, overheads) incurred to produce one unit of product. Monitoring unit cost supports pricing decisions and cost optimization efforts.', 'Azalması İyi', 'Para', 'Üretim', true, true, false, false),
('İşçi Başına Üretim Miktarı', 'Production Output per Worker', 'Belirli bir dönemde her üretim çalışanının ürettiği ortalama birim veya değer miktarı. Bu metriğin izlenmesi iş gücü verimliliği analizini ve süreç iyileştirme kararlarını destekler.', 'The average number of units or value produced per production worker in a given period. Monitoring this metric supports labor efficiency analysis and process improvement decisions.', 'Artması İyi', 'Sayı', 'Üretim', true, true, false, false),
('Hammadde İsraf Oranı', 'Raw Material Waste Rate', 'Üretim sürecinde kullanılan hammadde içinde atık veya kayıp olarak gerçekleşen miktarın yüzdesi. İsraf oranının düşürülmesi maliyetleri azaltır ve çevresel sürdürülebilirliği destekler.', 'The percentage of raw materials consumed in production that results in waste or loss. Reducing waste rates lowers costs and supports environmental sustainability.', 'Azalması İyi', 'Yüzde', 'Üretim', true, true, false, false),
('Kapasite Planlama Doğruluğu', 'Capacity Planning Accuracy', 'Tahmin edilen üretim kapasitesinin fiili kapasiteyle örtüşme yüzdesi. Yüksek planlama doğruluğu aşırı kapasite veya kapasite yetersizliğinden kaynaklanan maliyetleri azaltır.', 'The percentage alignment between forecasted and actual production capacity. High planning accuracy reduces costs from both overcapacity and capacity shortfalls.', 'Artması İyi', 'Yüzde', 'Üretim', true, true, false, false),
('Üretim Hattı Dengesi Etkinliği', 'Production Line Balance Efficiency', 'Üretim hattındaki iş istasyonları arasında iş yükünün dengeli dağılım oranı. Yüksek hat dengesi boşta bekleme sürelerini azaltır ve hat genel verimliliğini artırır.', 'The ratio of balanced workload distribution across workstations on a production line. High line balance efficiency reduces idle waiting times and improves overall line throughput.', 'Artması İyi', 'Yüzde', 'Üretim', true, true, false, false);
